import{_ as a,o as i,c as n,ag as t}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Training Plans","description":"","frontmatter":{},"headers":[],"relativePath":"training/index.md","filePath":"training/index.md"}'),s={name:"training/index.md"};function r(l,e,o,g,c,h){return i(),n("div",null,[...e[0]||(e[0]=[t('<h1 id="training-plans" tabindex="-1">Training Plans <a class="header-anchor" href="#training-plans" aria-label="Permalink to &quot;Training Plans&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Training plans connect analytics observations to actionable development work. The suggestion engine automatically identifies areas needing attention and proposes training focus areas. Coaches review suggestions and convert them to formal training plans.</p><h2 id="how-the-suggestion-engine-works" tabindex="-1">How the Suggestion Engine Works <a class="header-anchor" href="#how-the-suggestion-engine-works" aria-label="Permalink to &quot;How the Suggestion Engine Works&quot;">​</a></h2><p>After sufficient data is collected the app analyzes each player&#39;s stats and mechanics scores against configurable thresholds. When a metric falls below threshold a training suggestion is generated with:</p><ul><li>The specific issue identified</li><li>Priority level (High, Medium, or Low)</li><li>A suggested training focus</li><li>A link to search for relevant drills</li></ul><h2 id="dismissing-suggestions" tabindex="-1">Dismissing Suggestions <a class="header-anchor" href="#dismissing-suggestions" aria-label="Permalink to &quot;Dismissing Suggestions&quot;">​</a></h2><p>Each suggestion card has an <strong>X button</strong> to dismiss it. Dismissed suggestions:</p><ul><li>Are hidden immediately</li><li>Reappear after 30 days automatically</li><li>Reappear earlier if the underlying stat declines by more than 10% from when it was dismissed</li></ul><p>This prevents suggestion fatigue while ensuring important issues resurface.</p><h2 id="creating-a-training-plan" tabindex="-1">Creating a Training Plan <a class="header-anchor" href="#creating-a-training-plan" aria-label="Permalink to &quot;Creating a Training Plan&quot;">​</a></h2><ol><li>Tap <strong>Create Training Plan</strong> on a suggestion card or from the Training Plans screen</li><li>The plan is pre-populated with the player, training area, and suggested focus</li><li>Add specific drill notes and objectives</li><li>Save the plan</li></ol><h2 id="drill-search" tabindex="-1">Drill Search <a class="header-anchor" href="#drill-search" aria-label="Permalink to &quot;Drill Search&quot;">​</a></h2><p>Each training plan and suggestion includes a <strong>Find Drills</strong> button that searches YouTube for relevant coaching drills. The search is sport-aware — softball teams get softball-specific drill results.</p><h2 id="tracking-progress" tabindex="-1">Tracking Progress <a class="header-anchor" href="#tracking-progress" aria-label="Permalink to &quot;Tracking Progress&quot;">​</a></h2><p>As new game and practice data is logged the analytics update automatically. Training plans show whether the underlying metrics are improving, stable, or declining since the plan was created.</p><h2 id="analytics-settings" tabindex="-1">Analytics Settings <a class="header-anchor" href="#analytics-settings" aria-label="Permalink to &quot;Analytics Settings&quot;">​</a></h2><p>Head coaches can customize the thresholds that trigger suggestions through <strong>Settings → Analytics Settings</strong>. Age level presets are available for quick configuration:</p><ul><li>Recreational 8U–10U</li><li>Recreational 11U–12U</li><li>Travel 12U–14U</li><li>Travel 15U–18U</li><li>High School</li><li>Softball presets for all levels</li></ul>',19)])])}const p=a(s,[["render",r]]);export{u as __pageData,p as default};
